                new_weight = current_weight + model.req_rate / model.slo
                new_size = current_size + model.model_size

                if GPU_MEM - new_size > 0:
                    new_kvpr = new_weight / (GPU_MEM - new_size)
                    if gpu_id < len(placement) and len(placement[gpu_id]) > 0:
                        old_weight = current_weight
                        old_size = current_size
                        old_kvpr = old_weight / (GPU_MEM - old_size) if GPU_MEM - old_size > 0 else float('inf')
                        kvpr_improvement = new_kvpr - old_kvpr
                    else:
                        kvpr_improvement = new_kvpr

                    if kvpr_improvement < best_kvpr_improvement:
                        best_kvpr_improvement = kvpr_improvement
                        best_gpu = gpu_id

        # If we found a good GPU, assign the model
        if best_gpu != -1:
            placement[best_gpu].append(model)
            gpu_sizes[best_gpu] += model.model_size
        else:
            # Fallback: put on the GPU with most remaining space
            best_gpu = max(range(gpu_num), key=lambda i: GPU_MEM - gpu_sizes[i])
            if gpu_sizes[best_gpu] + model.model_size <= GPU_MEM:
                placement[best_gpu].append(model)
                gpu_sizes[best_gpu] += model.model_size
            else:
                # Last resort: put on the emptiest GPU if it can fit
                emptiest_gpu = min(range(gpu_num), key=lambda i: gpu_sizes[i])
                if gpu_sizes[emptiest_gpu] + model.model_size <= GPU_MEM:
                    placement[emptiest_gpu].append(model)
                    gpu_sizes[emptiest_gpu] += model.model_size
                else:
                    # If no GPU can fit, this shouldn't happen in valid inputs
                    # But if it does, put it on the empty GPU
                    for i in range(gpu_num):
                        if gpu_sizes[i] == 0:
                            placement[i].append(model)
                            gpu_sizes[i] = model.model_size
                            break

    # Optimize using local search
    current = {i: list(placement[i]) for i in range(gpu_num)}
    current_cost = max_kvpr(current)
    best = {i: list(current[i]) for i in range(gpu_num)}
    best_cost = current_cost

    import random
    import math

    # Simulated Annealing parameters
    temp = 1.0
    cooling = 0.999
    min_temp = 1e-6
    max_iter = 50000

    for iteration in range(max_iter):
        if temp < min_temp:
            break

        # Try a random move
        move_type = random.random()
        new_place = {i: list(current[i]) for i in range(gpu_num)}

        if move_type < 0.5:
            # Move a model from one GPU to another
            src_gpu = random.randint(0, gpu_num - 1)
