            model_idx = random.randint(0, len(new_place[src_gpu]) - 1)
            model = new_place[src_gpu][model_idx]

            # Find a suitable destination GPU
            dest_gpu = -1
            for i in range(gpu_num):
                if i != src_gpu and sum(m.model_size for m in new_place[i]) + model.model_size <= GPU_MEM:
                    dest_gpu = i
                    break

            if dest_gpu != -1:
                new_place[src_gpu].pop(model_idx)
                new_place[dest_gpu].append(model)
        elif move_type < 0.8:
            # Swap two models between GPUs
            gpus = [i for i in range(gpu_num) if new_place[i]]
            if len(gpus) < 2:
                continue

            gpu1, gpu2 = random.sample(gpus, 2)
            if not new_place[gpu1] or not new_place[gpu2]:
