            idx1 = random.randint(0, len(new_place[gpu1]) - 1)
            idx2 = random.randint(0, len(new_place[gpu2]) - 1)

            model1 = new_place[gpu1][idx1]
            model2 = new_place[gpu2][idx2]

            # Check if both can accommodate the swap
            size1 = sum(m.model_size for m in new_place[gpu1]) - model1.model_size + model2.model_size
            size2 = sum(m.model_size for m in new_place[gpu2]) - model2.model_size + model1.model_size

            if size1 <= GPU_MEM and size2 <= GPU_MEM:
                new_place[gpu1][idx1], new_place[gpu2][idx2] = model2, model1
        else:
            # Move a model to the GPU with the lowest current KVPR
            src_gpu = random.randint(0, gpu_num - 1)
            if not new_place[src_gpu]:
                continue

            model_idx = random.randint(0, len(new_place[src_gpu]) - 1)
            model = new_place[src_gpu][model_idx]

            # Find the GPU with lowest current KVPR (excluding source)
            min_kvpr_gpu = -1
            min_kvpr = float('inf')
            for i in range(gpu_num):
                if i == src_gpu:
                    continue
                if sum(m.model_size for m in new_place[i]) + model.model_size <= GPU_MEM:
                    current_kvpr = kvpr_for_gpu(new_place[i])
                    if current_kvpr < min_kvpr:
                        min_kvpr = current_kvpr
                        min_kvpr_gpu = i

            if min_kvpr_gpu != -1:
                new_place[src_gpu].pop(model_idx)
                new_place[min_kvpr_gpu].append(model)

        # Check if this change is beneficial
        new_cost = max_kvpr(new_place)
        delta = new_cost - current_cost

        if delta < 0 or random.random() < math.exp(-delta / temp):
            current = new_place
            current_cost = new_cost

            if new_cost < best_cost:
                best = {i: list(new_place[i]) for i in range(gpu_num)}
                best_cost = new_cost

        temp *= cooling

    # Final local search to fine-tune
    for _ in range(10000):
        improved = False
        for src in range(gpu_num):
            if not best[src]:
                continue
            for dst in range(gpu_num):
                if src == dst:
                    continue
                for i in range(len(best[src])):
                    model = best[src][i]
                    size1 = sum(m.model_size for m in best[src]) - model.model_size
                    size2 = sum(m.model_size for m in best[dst]) + model.model_size

                    if size1 + model.model_size <= GPU_MEM and size2 <= GPU_MEM:
                        test_placement = {i: list(best[i]) for i in range(gpu_num)}
                        test_placement[src].pop(i)
                        test_placement[dst].append(model)

                        if max_kvpr(test_placement) < best_cost:
                            best = test_placement
                            best_cost = max_kvpr(test_placement)
                            improved = True
                            break
            if improved:
                break
        if not improved:
            break

    return best

def compute_model_placement(gpu_num, models):
    def calculate_kvpr_for_gpu(gpu_models):
        if not gpu_models:
            return 0
        total_size = sum(m.model_size for m in gpu_models)
        total_weighted_rate = sum(m.req_rate / m.slo for m in gpu_models)
        if total_size >= 80:
            return float('inf')
        return total_weighted_rate / (80 - total_size)

    # Sort models by model_size in descending order (first fit decreasing)
    sorted_models = sorted(models, key=lambda m: m.model_size, reverse=True)

    # Initialize placement
    placement = {i: [] for i in range(gpu_num)}
    gpu_sizes = [0] * gpu_num
    gpu_weights = [0.0] * gpu_num

    # First fit decreasing
    for model in sorted_models:
        best_gpu = -1
        best_kvpr = float('inf')

        # Find best GPU that can accommodate the model
        for gpu_id in range(gpu_num):
            if gpu_sizes[gpu_id] + model.model_size <= 80:
                # Calculate new KVPR if we add this model
                new_size = gpu_sizes[gpu_id] + model.model_size
                new_weight = gpu_weights[gpu_id] + model.req_rate / model.slo
                new_kvpr = new_weight / (80 - new_size)

                if new_kvpr < best_kvpr:
                    best_kvpr = new_kvpr
                    best_gpu = gpu_id

        # If no GPU was suitable, put it on the one with most remaining space
        if best_gpu == -1:
            best_gpu = max(range(gpu_num), key=lambda i: 80 - gpu_sizes[i])

        placement[best_gpu].append(model)
        gpu_sizes[best_gpu] += model.model_size
        gpu_weights[best_gpu] += model.req_rate / model.slo

    # Local search: try swapping models between GPUs
    def get_max_kvpr():
        return max(calculate_kvpr_for_gpu(placement[gpu_id]) for gpu_id in range(gpu_num))

    max_kvpr = get_max_kvpr()
    improved = True

    while improved:
        improved = False
        for gpu1 in range(gpu_num):
            for gpu2 in range(gpu_num):
                if gpu1 == gpu2:
                    continue
                for i, model1 in enumerate(placement[gpu1]):
                    for j, model2 in enumerate(placement[gpu2]):
                        # Check if swapping is valid
                        new_size1 = gpu_sizes[gpu1] - model1.model_size + model2.model_size
                        new_size2 = gpu_sizes[gpu2] - model2.model_size + model1.model_size

                        if new_size1 <= 80 and new_size2 <= 80:
                            # Calculate potential new KVPR
                            old_kvpr1 = calculate_kvpr_for_gpu(placement[gpu1])
                            old_kvpr2 = calculate_kvpr_for_gpu(placement[gpu2])

                            new_placement = {i: list(placement[i]) for i in range(gpu_num)}
                            new_placement[gpu1][i] = model2
                            new_placement[gpu2][j] = model1

                            new_kvpr1 = calculate_kvpr_for_gpu(new_placement[gpu1])
                            new_kvpr2 = calculate_kvpr_for_gpu(new_placement[gpu2])

                            # Check if overall max KVPR improves
                            old_max = max(old_kvpr1, old_kvpr2)
                            new_max = max(new_kvpr1, new_kvpr2)

                            if new_max < old_max - 1e-9:  # Avoid floating point precision issues
                                placement = new_placement
                                gpu_sizes[gpu1] = new_size1
                                gpu_sizes[gpu2] = new_size2
                                gpu_weights[gpu1] = sum(m.req_rate / m.slo for m in placement[gpu1])
                                gpu_weights[gpu2] = sum(m.req_rate / m.slo for m in placement[gpu2])
                                max_kvpr = new_max
                                improved = True
                                break
                    if improved:
                        break
            if improved:
                break

    return placement

