def compute_model_placement(gpu_num, models):
    """
    Assign models to GPUs to minimize max KVPR using a more sophisticated approach.

    Args:
        gpu_num: Number of GPUs (int, 5-10)
        models: List of model objects with .model_size, .req_rate, .slo attributes

    Returns:
        dict mapping gpu_id (int) to list of models assigned to that GPU
    """
    GPU_MEM_SIZE = 80  # GB

    # Preprocess models with weighted rate
    model_data = []
    for model in models:
        model_data.append({
            'obj': model,
            'size': model.model_size,
            'weight': model.req_rate / model.slo,
        })

    # Sort by weighted rate descending for greedy assignment
    model_data.sort(key=lambda x: x['weight'], reverse=True)

    # Initialize GPU states
    gpu_states = []
    for i in range(gpu_num):
        gpu_states.append({
            'id': i,
            'used_size': 0,
            'used_weight': 0.0,
            'models': []
        })

    # Greedy assignment with better heuristic
    for model in model_data:
        best_gpu_idx = -1
        min_max_kvpr = float('inf')

        # Try to place on each GPU
        for i in range(gpu_num):
            if gpu_states[i]['used_size'] + model['size'] <= GPU_MEM_SIZE:
                # Calculate max KVPR if we place this model on GPU i
                temp_states = []
                for j, state in enumerate(gpu_states):
                    if j == i:
                        temp_states.append({
                            'used_size': state['used_size'] + model['size'],
                            'used_weight': state['used_weight'] + model['weight']
                        })
                    else:
                        temp_states.append({
                            'used_size': state['used_size'],
                            'used_weight': state['used_weight']
                        })

                # Calculate max KVPR across all GPUs
                max_kvpr = 0.0
                for state in temp_states:
                    if state['used_size'] < GPU_MEM_SIZE and state['used_weight'] > 0:
                        kvpr = state['used_weight'] / (GPU_MEM_SIZE - state['used_size'])
                        max_kvpr = max(max_kvpr, kvpr)
                    elif state['used_weight'] > 0:
                        max_kvpr = float('inf')

                if max_kvpr < min_max_kvpr:
                    min_max_kvpr = max_kvpr
                    best_gpu_idx = i

        # If no valid placement found, place on GPU with most remaining space
        if best_gpu_idx == -1:
            best_gpu_idx = max(range(gpu_num), 
                              key=lambda i: GPU_MEM_SIZE - gpu_states[i]['used_size'])

        # Assign the model
        gpu_states[best_gpu_idx]['used_size'] += model['size']
        gpu_states[best_gpu_idx]['used_weight'] += model['weight']
        gpu_states[best_gpu_idx]['models'].append(model['obj'])

    # Return result in required format
    result = {}
    for state in gpu_states:
        result[state['id']] = state['models']

    return result
